const errorData = $input.first().json;

// Extract useful error details from the n8n error trigger payload
const execution = errorData.execution || {};
const workflow = errorData.workflow || {};
const lastNodeExecuted = execution.lastNodeExecuted || 'Unknown';

// Get error message from the execution data
let errorMessage = 'Unknown error';
let errorStack = '';
try {
  const resultData = execution.data?.resultData;
  if (resultData?.error) {
    errorMessage = resultData.error.message || resultData.error.description || String(resultData.error);
    errorStack = resultData.error.stack || '';
  } else if (resultData?.runData) {
    // Try to find the failed node's error
    const nodeData = resultData.runData[lastNodeExecuted];
    if (nodeData && nodeData[0]?.error) {
      errorMessage = nodeData[0].error.message || String(nodeData[0].error);
      errorStack = nodeData[0].error.stack || '';
    }
  }
} catch (e) {
  errorMessage = 'Could not parse error details: ' + e.message;
}

const now = new Date().toISOString();

return [{ json: {
  timestamp: now,
  workflowId: workflow.id || 'Unknown',
  workflowName: workflow.name || 'Unknown',
  executionId: execution.id || 'Unknown',
  lastNodeExecuted: lastNodeExecuted,
  errorMessage: errorMessage,
  errorStack: errorStack.substring(0, 1000),
  executionUrl: execution.url || '',
  severity: 'ERROR',
  source: 'OpsBlueprint n8n Workflows'
} }];

const err = $input.first().json;

console.error(`[OPSBLUEPRINT ERROR HANDLER] ${err.timestamp}`);
console.error(`  Workflow: ${err.workflowName} (${err.workflowId})`);
console.error(`  Execution: ${err.executionId}`);
console.error(`  Failed Node: ${err.lastNodeExecuted}`);
console.error(`  Error: ${err.errorMessage}`);
if (err.errorStack) {
  console.error(`  Stack: ${err.errorStack.substring(0, 500)}`);
}

const emailHtml = `
<div style="font-family: 'Segoe UI', Arial, sans-serif; max-width: 600px; margin: 0 auto;">
  <div style="background: #dc3545; padding: 15px 20px; border-radius: 6px 6px 0 0;">
    <h2 style="color: #fff; margin: 0; font-size: 16px;">n8n Workflow Error — OpsBlueprint</h2>
  </div>
  <div style="background: #f8f9fa; padding: 20px; border: 1px solid #dee2e6; border-top: none;">
    <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
      <tr><td style="padding: 6px 8px; font-weight: bold; width: 130px;">Timestamp</td><td style="padding: 6px 8px;">${err.timestamp}</td></tr>
      <tr style="background: #fff;"><td style="padding: 6px 8px; font-weight: bold;">Workflow</td><td style="padding: 6px 8px;">${err.workflowName}</td></tr>
      <tr><td style="padding: 6px 8px; font-weight: bold;">Execution ID</td><td style="padding: 6px 8px;"><code>${err.executionId}</code></td></tr>
      <tr style="background: #fff;"><td style="padding: 6px 8px; font-weight: bold;">Failed Node</td><td style="padding: 6px 8px;"><code>${err.lastNodeExecuted}</code></td></tr>
    </table>
    <div style="margin-top: 15px; padding: 12px; background: #fff3cd; border: 1px solid #ffc107; border-radius: 4px;">
      <strong>Error Message:</strong><br>
      <code style="word-break: break-all;">${err.errorMessage}</code>
    </div>
    ${err.executionUrl ? `<p style="margin-top: 15px;"><a href="${err.executionUrl}" style="color: #0d6efd;">View Execution Details</a></p>` : ''}
  </div>
  <div style="background: #e9ecef; padding: 10px 20px; border-radius: 0 0 6px 6px; font-size: 12px; color: #6c757d;">
    OpsBlueprint Automation Monitor | ${err.timestamp}
  </div>
</div>`;

const emailSubject = `[ALERT] OpsBlueprint n8n Error: ${err.workflowName} — ${err.lastNodeExecuted}`;

return [{ json: { ...err, emailHtml, emailSubject } }];

const err = $input.first().json;

const tenantId = $env.MS_GRAPH_TENANT_ID;
const clientId = $env.MS_GRAPH_CLIENT_ID;
const clientSecret = $env.MS_GRAPH_CLIENT_SECRET;
const mailUserUpn = $env.MAIL_USER_UPN;

if (!tenantId || !clientId || !clientSecret || !mailUserUpn) {
  console.error('[OB ERROR HANDLER] MS Graph credentials not configured, skipping email notification');
  return [{ json: { ...err, emailSent: false, reason: 'MS Graph credentials not configured' } }];
}

return [{ json: {
  ...err,
  tenantId,
  clientId,
  clientSecret,
  mailUserUpn,
  shouldSendEmail: true
} }];

const err = $('Check Email Credentials').first().json;
console.error('[OB ERROR HANDLER] Notification skipped — no Graph credentials');
return [{ json: { emailSent: false, workflowName: err.workflowName, errorMessage: err.errorMessage } }];
